select ti.id track_id, ti.album_id, ti.track_title, ti.cover_url, ti.media_duration, ti.status, max(if(ts.stat_type = '0701',stat_num,-1)) playStatNum, max(if(ts.stat_type = '0702',stat_num,-1)) collectStatNum, max(if(ts.stat_type = '0703',stat_num,-1)) praiseStatNum, max(if(ts.stat_type = '0704',stat_num,-1)) commentStatNum from track_info ti inner join track_stat ts on ti.id = ts.track_id
ti.user_id = #{trackInfoQuery.getUserId}
and ts.stat_type = #{trackInfoQuery.getStatus}
and ti.track_title like concat('%', #{trackInfoQuery.getTrackTitle}, '%')
group by ti.id order by ti.id desc
